#[derive(Clone, Copy, Debug, Eq, PartialEq, Ord, PartialOrd)]
#[repr(usize)]
pub enum LockRank {
    Unknown = 0,
    /// IRQ-enabled cross-CPU serializers. This rank precedes the
    /// scheduler because an IPI handler may acquire scheduler state.
    CrossCpu = 15,
    /// Hard-IRQ-safe timer bases. A timer interrupt may preempt a
    /// task which holds an IRQ-enabled CrossCpu serializer, so Timer
    /// must remain after CrossCpu and before Scheduler.
    Timer = 16,
    /// IRQ-safe deferred-work bases. Publication may wake a task, so this
    /// rank remains after Timer and before Scheduler.
    WorkQueue = 17,
    Scheduler = 20,
    WaitQueue = 30,
    /// Process and thread-group metadata. Process state may lead into VM
    /// state, but VM teardown must not call back into this rank.
    Process = 35,
    Vfs = 36,
    Vm = 40,
    PageTable = 50,
    Heap = 60,
    PageAllocator = 70,
    Console = 80,
}

// M9 process metadata may lead into VM state, never the reverse.
const _: () = {
    assert!((LockRank::WaitQueue as usize) < (LockRank::Process as usize));
    assert!((LockRank::Process as usize) < (LockRank::Vm as usize));
    assert!((LockRank::Vfs as usize) < (LockRank::Vm as usize));
};

// M6-B deferred-execution lock order.
const _: () = {
    assert!((LockRank::CrossCpu as usize) < (LockRank::Timer as usize));
    assert!((LockRank::Timer as usize) < (LockRank::WorkQueue as usize));
    assert!((LockRank::WorkQueue as usize) < (LockRank::Scheduler as usize));
};

// hardirq timer rank must follow IRQ-enabled serializers.
const _: () = {
    assert!((LockRank::CrossCpu as usize) < (LockRank::Timer as usize));
    assert!((LockRank::Timer as usize) < (LockRank::Scheduler as usize));
};

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub struct LockClass {
    pub name: &'static str,
    pub rank: LockRank,
    pub order: usize,
}

impl LockClass {
    pub const fn new(name: &'static str, rank: LockRank, order: usize) -> Self {
        Self { name, rank, order }
    }

    pub const fn unknown() -> Self {
        Self::new("unknown", LockRank::Unknown, 0)
    }

    const fn key(self) -> usize {
        (self.rank as usize) * 1024 + self.order
    }
}

/// Validate a lock whose payload is deliberately held with local IRQs enabled.
///
/// Timer hardirqs can interrupt such a critical section, therefore every
/// IRQ-enabled outer lock must precede the Timer rank. This is the small-kernel
/// equivalent of Linux lockdep's hardirq-unsafe -> hardirq-safe dependency rule.
pub fn assert_irq_enabled_outer_lock(class: LockClass) {
    assert!(
        class.rank < LockRank::Timer,
        "IRQ-enabled tracked lock must precede hardirq timer locks: lock={} rank={:?} timer_rank={:?}",
        class.name,
        class.rank,
        LockRank::Timer,
    );
}

