pub fn current_pc() -> VirtAddr {
    let value: usize;

    // SAFETY:
    // pcaddi 只计算当前 PC，不访问内存。
    unsafe {
        asm!(
            "pcaddi {value}, 0",
            value = out(reg) value,
            options(nomem, nostack),
        );
    }

    VirtAddr::new(value)
