/// Proc 文件内容生成器。
///
/// 每次 read 时调用 `generate()` 动态生成完整文件内容。
/// 返回的字节被缓存在文件位置中（简化实现）。
pub trait ProcFileGenerator: Send + Sync + 'static {
    /// 生成文件内容。
    fn generate(&self) -> Result<Vec<u8>, Errno>;
}

