        let heap = unsafe { self.heap.get_mut_unchecked() };
        if heap.is_some() {
            return Err(HeapInstallError::AlreadyInitialized);
        }
        *heap = Some(HeapAllocator::new(KernelPageProvider));
        Ok(())
    }
    pub fn is_initialized(&self) -> bool {
        self.heap.lock().is_some()
    }

