ENTRY(_start)

BOOT_PHYS_BASE   = 0x80200000;
KERNEL_PHYS_BASE = 0x80400000;
KERNEL_VIRT_BASE = 0xffffffff80000000;

BOOT_STACK_SIZE = 64K;
SMP_BOOT_STACKS_SIZE = 512K;

SECTIONS
{
    /*
     * 第一阶段启动代码。
     *
     * VMA 和 LMA 都是低物理地址，因此 OpenSBI 可以直接跳入。
     */
    . = BOOT_PHYS_BASE;

    __boot_phys_start = .;

    .boot.text : ALIGN(4K)
{
    KEEP(*(.boot.text.entry))
    *(.boot.text .boot.text.*)
}

.boot.rodata : ALIGN(4K)
{
    KEEP(*(.boot.rodata .boot.rodata.*))
}

.boot.data : ALIGN(4K)
{
    *(.boot.data .boot.data.*)
}

.boot.bss (NOLOAD) : ALIGN(4K)
{
    __boot_bss_start = .;

    *(.boot.bss .boot.bss.*)

    . = ALIGN(4K);
    __boot_bss_end = .;
}

    __boot_phys_end = .;

    /*
     * Secondary harts enter with satp=0.  Keep a single supervisor-only
     * identity-mapped trampoline page separate from the discarded boot map,
     * so the instruction immediately following the satp write remains valid.
     */
    ASSERT(__boot_phys_end <= 0x80300000, "RISC-V boot image overlaps SMP trampoline")
    . = 0x80300000;

    .smp_trampoline : ALIGN(4K)
    {
        __smp_trampoline_start = .;
        KEEP(*(.smp.trampoline))
        . = ALIGN(4K);
        __smp_trampoline_end = .;
        ASSERT(__smp_trampoline_end - __smp_trampoline_start <= 4K,
               "RISC-V SMP trampoline exceeds one page")
    }

    /*
     * 正式高半内核。
     *
     * VMA 从 0xffffffff80000000 开始，
     * LMA 从物理地址 0x80400000 开始。
     */
    . = KERNEL_VIRT_BASE;

    __kernel_start = .;

    .text : AT(
    KERNEL_PHYS_BASE
    + (ADDR(.text) - KERNEL_VIRT_BASE)
)
{
    __text_start = .;

    KEEP(*(.text.high_entry))
    *(.text .text.*)

    . = ALIGN(4K);
    __text_end = .;
}

    .rodata : AT(
        KERNEL_PHYS_BASE
        + (ADDR(.rodata) - KERNEL_VIRT_BASE)
    ) ALIGN(4K)
    {
        __rodata_start = .;

        *(.rodata .rodata.*) *(.srodata .srodata.*) *(.srodata.cst* .srodata.cst.*) *(.sdata2 .sdata2.*) *(.data.rel.ro .data.rel.ro.*) *(.gnu.linkonce.r.*)

        . = ALIGN(4K); __rodata_end = .;
    }

    . = ALIGN(0x1000); /* OSKernel2026: page-align first writable RISC-V PT_LOAD */
    .data : AT(
        KERNEL_PHYS_BASE
        + (ADDR(.data) - KERNEL_VIRT_BASE)
    )
    {
        __data_start = .;

        *(.data .data.*)

        . = ALIGN(16);

        /*
         * RISC-V small-data global pointer。
         */
        PROVIDE(__global_pointer$ = . + 0x800);

        *(.sdata .sdata.*)
        *(.got .got.*)

        . = ALIGN(4K);
        __data_end = .;
    }

    .bss (NOLOAD) : AT(
        KERNEL_PHYS_BASE
        + (ADDR(.bss) - KERNEL_VIRT_BASE)
    )
    {
        __bss_start = .;

        *(.sbss .sbss.*)
        *(.bss .bss.*)
        *(COMMON)

        . = ALIGN(4K);
        __bss_end = .;
    }

    .boot_stack (NOLOAD) : AT(
        KERNEL_PHYS_BASE
        + (ADDR(.boot_stack) - KERNEL_VIRT_BASE)
    )
    {
        __boot_stack_bottom = .;

        . += BOOT_STACK_SIZE;

        . = ALIGN(4K);
        __boot_stack_top = .;
    }

    .smp_boot_stacks (NOLOAD) : AT(
        KERNEL_PHYS_BASE
        + (ADDR(.smp_boot_stacks) - KERNEL_VIRT_BASE)
    )
    {
        __smp_boot_stack_bottom = .;

        . += SMP_BOOT_STACKS_SIZE;

        . = ALIGN(4K);
        __smp_boot_stack_top = .;
    }

    . = ALIGN(4K);

    __kernel_end = .;

    /*
     * 正式高半段对应的低物理范围。
     */
    __text_phys_start = LOADADDR(.text);
    __text_phys_end =
        LOADADDR(.text) + SIZEOF(.text);

    __rodata_phys_start = LOADADDR(.rodata);
    __rodata_phys_end =
        LOADADDR(.rodata) + SIZEOF(.rodata);

    __rw_phys_start = LOADADDR(.data);
    __rw_phys_end =
        LOADADDR(.smp_boot_stacks)
        + SIZEOF(.smp_boot_stacks);

    /*
     * 内存分配器必须保留完整范围：
     *
     * .boot
     * 0x802... 到 0x804... 的间隙
     * 正式高半内核的所有 LMA
     */
    __kernel_phys_start = BOOT_PHYS_BASE;
    __kernel_phys_end = __rw_phys_end;

    /DISCARD/ :
    {
        *(.eh_frame .eh_frame.*)
        *(.comment)
    }
}

use core::arch::asm;

const SSTATUS_SIE: usize = 1 << 1;

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
#[must_use = "saved interrupt state should be restored"]
pub struct InterruptState {
    enabled: bool,
}

impl InterruptState {
    pub const fn was_enabled(self) -> bool {
        self.enabled
    }
}

pub fn save_and_disable() -> InterruptState {
    let previous: usize;

    // SAFETY: 只原子清除当前 hart 的 SIE 位并读取旧 sstatus。
    unsafe {
        asm!(
            "csrrc {previous}, sstatus, {mask}",
            previous = out(reg) previous,
            mask = in(reg) SSTATUS_SIE,
            options(nostack),
        );
    }

    InterruptState {
        enabled: previous & SSTATUS_SIE != 0,
    }
}

pub fn restore(state: InterruptState) {
    if state.was_enabled() {
        // SAFETY: 恢复当前 hart 的 SIE 位，不访问内存或栈。
        unsafe {
            asm!(
                "csrs sstatus, {mask}",
                mask = in(reg) SSTATUS_SIE,
                options(nostack),
            );
        }
    } else {
        // SAFETY: 清除当前 hart 的 SIE 位，不访问内存或栈。
        unsafe {
            asm!(
                "csrc sstatus, {mask}",
                mask = in(reg) SSTATUS_SIE,
                options(nostack),
            );
        }
    }
}

pub fn disable() {
    // SAFETY: 清除当前 hart 的 SIE 位，不访问内存或栈。
    unsafe {
        asm!(
            "csrc sstatus, {mask}",
            mask = in(reg) SSTATUS_SIE,
            options(nostack),
        );
    }
}

/// # Safety
///
/// 调用者必须保证异常入口、栈以及所有可能的中断控制器均已配置。
pub unsafe fn enable() {
    // SAFETY: 调用者保证 trap entry、栈和中断控制器状态已准备好。
    unsafe {
        asm!(
            "csrs sstatus, {mask}",
            mask = in(reg) SSTATUS_SIE,
            options(nostack),
        );
    }
}

pub fn mask_all_sources() {
    // SAFETY: this masks every supervisor-local interrupt source on the
    // current hart without changing global interrupt state.
    unsafe {
        asm!("csrw sie, zero", options(nostack));
    }
}

pub fn are_enabled() -> bool {
    let status: usize;

    // SAFETY: 只读取当前 hart 的 sstatus CSR。
    unsafe {
        asm!(
            "csrr {status}, sstatus",
            status = out(reg) status,
            options(nostack),
        );
    }

    status & SSTATUS_SIE != 0
}

pub fn are_disabled() -> bool {
    !are_enabled()
}

use core::arch::asm;

const CRMD_IE: usize = 1 << 2;
const CSR_ECFG: usize = 0x4;
const ECFG_INTERRUPT_MASK: usize = 0x1fff;

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
#[must_use = "saved interrupt state should be restored"]
pub struct InterruptState {
    enabled: bool,
}

impl InterruptState {
    pub const fn was_enabled(self) -> bool {
        self.enabled
    }
}

fn exchange_interrupt_enable(new_value: usize) -> usize {
    let mut value = new_value;

    // SAFETY: csrxchg 只修改当前 CPU 的 CRMD.IE 位并返回旧 CRMD。
    unsafe {
        asm!(
            "csrxchg {value}, $r12, 0x0",
            value = inout(reg) value,
            in("$r12") CRMD_IE,
            options(nostack),
        );
    }

    value
}

pub fn save_and_disable() -> InterruptState {
    let previous = exchange_interrupt_enable(0);

    InterruptState {
        enabled: previous & CRMD_IE != 0,
    }
}

pub fn restore(state: InterruptState) {
    let value = if state.was_enabled() { CRMD_IE } else { 0 };

    exchange_interrupt_enable(value);
}

pub fn disable() {
    exchange_interrupt_enable(0);
}

/// # Safety
///
/// 调用者必须保证异常入口、栈以及中断控制器已经正确配置。
pub unsafe fn enable() {
    exchange_interrupt_enable(CRMD_IE);
}

pub fn mask_all_sources() {
    let value: usize = 0;

    // SAFETY: clear only ECFG.LIE[12:0], preserving vector-spacing and all
    // reserved fields.  r12 is used only as the CSRXCHG mask operand.
    unsafe {
        asm!(
            "csrxchg {value}, $r12, {csr}",
            value = inout(reg) value => _,
            in("$r12") ECFG_INTERRUPT_MASK,
            csr = const CSR_ECFG,
            options(nomem, nostack),
        );
    }
}

pub fn are_enabled() -> bool {
    let value: usize;

    // SAFETY: 只读取当前 CPU 的 CRMD CSR。
    unsafe {
        asm!(
            "csrrd {value}, 0x0",
            value = out(reg) value,
            options(nostack),
        );
    }

    value & CRMD_IE != 0
}

pub fn are_disabled() -> bool {
    !are_enabled()
}

